// Push Prisma schema to Turso DB.
// Reads prisma/turso-schema.sql (generated by `prisma migrate diff --script`),
// strips Prisma CLI warning lines, executes each statement against Turso.
//
// Usage (PowerShell):
//   $env:DATABASE_URL = "libsql://...turso.io"
//   $env:TURSO_AUTH_TOKEN = "eyJ..."
//   node scripts/push-schema-to-turso.mjs

import { createClient } from "@libsql/client";
import { readFileSync } from "fs";

const url = process.env.DATABASE_URL;
const authToken = process.env.TURSO_AUTH_TOKEN;

if (!url?.startsWith("libsql:")) {
  console.error("ERROR: DATABASE_URL must be a libsql:// Turso URL");
  process.exit(1);
}
if (!authToken) {
  console.error("ERROR: TURSO_AUTH_TOKEN is required");
  process.exit(1);
}

const raw = readFileSync("./prisma/turso-schema.sql", "utf8");

// Strip Prisma CLI warning lines that pollute the SQL output
const cleaned = raw
  .split("\n")
  .filter((line) => {
    const t = line.trimStart();
    return !t.startsWith("warn ") && !t.startsWith("For more ");
  })
  .join("\n");

// Split by ; — each statement may have leading -- comments which are OK for SQLite
const statements = cleaned
  .split(";")
  .map((s) => s.trim())
  .filter((s) => {
    // Skip empty + skip statements that are ONLY comments (no SQL keyword)
    if (s.length === 0) return false;
    const noComments = s
      .split("\n")
      .filter((l) => !l.trim().startsWith("--"))
      .join("\n")
      .trim();
    return noComments.length > 0;
  });

console.log(`Found ${statements.length} SQL statements`);

const client = createClient({ url, authToken });

let ok = 0;
let failed = 0;
for (const stmt of statements) {
  const preview = stmt
    .split("\n")
    .find((l) => l.trim() && !l.trim().startsWith("--"))
    ?.slice(0, 70) ?? stmt.slice(0, 70);
  try {
    await client.execute(stmt);
    console.log(`  ✓ ${preview}`);
    ok++;
  } catch (e) {
    console.error(`  ✗ ${preview}`);
    console.error(`    ${e.message}`);
    failed++;
  }
}

console.log(`\n✅ Applied: ${ok}/${statements.length}`);
if (failed > 0) console.log(`⚠️  Failed: ${failed}`);

client.close();
